// Client-side SQLite schema — generated by the PowerSync dashboard (Client SDK
// Setup) from the deployed Sync Streams, converted from TS to JS. PowerSync adds
// an implicit `id` TEXT primary key to every table, so `id` is not declared.
// For composite-key tables the streams alias workspace + natural key into `id`;
// the original column still arrives via SELECT * and is declared below. jsonb columns sync as
// JSON text; booleans as 0/1 integers. Keep in step with powersync/sync-rules.yaml.

import { column, Schema, Table } from "@powersync/web";

// trackPrevious on shared documents/composite-key tables: uploads need the
// ancestor for three-way folds; DELETE ops also need previous workspace/key
// values when queued under a different workspace than the active one.
const service_tables = new Table(
  {
    // id column (text) is automatically included
    table_id: column.integer,
    data: column.text,
    updated_at: column.text,
    workspace_id: column.text,
  },
  { indexes: {}, trackPrevious: true },
);

const service_settings = new Table(
  {
    // id column (text) is automatically included
    state: column.text,
    updated_at: column.text,
    workspace_id: column.text,
  },
  { indexes: {}, trackPrevious: true },
);

const reservations = new Table(
  {
    // id column (text) is automatically included
    date: column.text,
    table_id: column.integer,
    data: column.text,
    created_at: column.text,
    workspace_id: column.text,
  },
  // Reservation data is a busy shared document (planner + terrace + service).
  // Its upload fold needs the device's pre-edit ancestor to preserve changes
  // made on another device while this op was offline.
  { indexes: {}, trackPrevious: true },
);

