    nut_free: column.text,
    pescetarian: column.text,
    no_red_meat: column.text,
    no_pork: column.text,
    no_game: column.text,
    no_offal: column.text,
    egg_free: column.text,
    menu_si: column.text,
    course_key: column.text,
    optional_flag: column.text,
    section_gap_before: column.integer,
    show_on_short: column.integer,
    short_order: column.integer,
    force_pairing_title: column.text,
    force_pairing_sub: column.text,
    kitchen_note: column.text,
    vegan: column.text,
    shellfish_free: column.text,
    no_alcohol: column.text,
    no_garlic_onion: column.text,
