const service_archive = new Table(
  {
    // id column (text) is automatically included
    date: column.text,
    label: column.text,
    state: column.text,
    created_at: column.text,
    deleted_at: column.text,
    workspace_id: column.text,
  },
  { indexes: {} },
);

export const AppSchema = new Schema({
  service_tables,
  service_settings,
  reservations,
  menu_courses,
  wines,
  beverages,
  service_archive,
});
